options.afterRender:
const root = typeof document !== "undefined" ? document : null;
if (root) {
  root.querySelectorAll(".puda-bubble").forEach((bubble) => {
    const text = bubble.querySelector(".puda-bubble-text");
    const button = bubble.querySelector(".puda-show-more");
    if (!text || !button) return;
    const overflowing = text.scrollHeight > text.clientHeight + 2;
    bubble.classList.toggle("puda-overflowing", overflowing);
    button.onclick = () => {
      bubble.classList.toggle("puda-expanded");
      button.textContent = bubble.classList.contains("puda-expanded") ? "Show less" : "Show more";
    };
  });
}

const root = typeof document !== "undefined" ? document : null;
if (root) {
  root.querySelectorAll(".puda-action-card").forEach((card) => {
    const body = card.querySelector(".puda-action-body");
    const button = card.querySelector(".puda-tool-show-more");
    if (!body || !button) return;
    const overflowing = body.scrollHeight > body.clientHeight + 2;
    card.classList.toggle("puda-tool-overflowing", overflowing);
    button.onclick = () => {
      card.classList.toggle("puda-tool-expanded");
      button.textContent = card.classList.contains("puda-tool-expanded") ? "Show less" : "Show more";
    };
  });
}
